1	const BASE_PRICES: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
11	const FIXED_FEE = 5;
12	
13	function applyFirstInsuranceSurcharge(amount: number): number {
14	  return Math.ceil((amount * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT)) / 100);
15	}
16	
17	function quotePremium(item: { type: string }): number {
18	  const basePrice = BASE_PRICES[item.type];
19	  return applyFirstInsuranceSurcharge(basePrice) + FIXED_FEE;
20	}
21	
22	export function runScenario(scenario: any): unknown {
23	  const item = scenario.steps[0].items[0];
24	  const premium = quotePremium(item);
25	  return { results: [{ premium }] };
26	}
